What does the following program print?

```cpp
#include <iostream>
#include <array>
int main()
{
    std::array<int, 4> a { 3, 1, 4, 2 };
    int n = static_cast<int>(a.size());
    for (int i = 0; i < n - 1; ++i)
    {
        int minIdx = i;
        for (int j = i + 1; j < n; ++j)
            if (a[j] < a[minIdx]) minIdx = j;
        int tmp = a[i]; a[i] = a[minIdx]; a[minIdx] = tmp;
    }
    for (int i = 0; i < n; ++i)
        std::cout << a[i] << ' ';
    std::cout << '\n';
    return 0;
}
```

